css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #020c1b; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 60px; height: 72px; border-bottom: 1px solid rgba(6,182,212,0.15); }
.logo { font-size: 22px; font-weight: 800; }
.links { display: flex; gap: 28px; } .links a { color: #94a3b8; text-decoration: none; font-weight: 500; }
.cta { padding: 10px 22px; border-radius: 10px; border: 1px solid #06b6d4; background: rgba(6,182,212,0.1); color: #06b6d4; font-weight: 700; cursor: pointer; }
.hero { padding: 80px 60px; text-align: center; }
.tag { display: inline-block; padding: 8px 18px; border-radius: 20px; background: rgba(6,182,212,0.1); border: 1px solid rgba(6,182,212,0.3); color: #06b6d4; font-size: 14px; font-weight: 600; margin-bottom: 28px; }
h1 { font-size: 72px; font-weight: 900; letter-spacing: -3px; line-height: 1; margin-bottom: 24px; } h1 span { color: #06b6d4; }
.hero p { font-size: 20px; color: #94a3b8; max-width: 560px; margin: 0 auto 36px; line-height: 1.7; }
.email-form { display: flex; gap: 12px; max-width: 480px; margin: 0 auto 16px; }
.email-form input { flex: 1; height: 52px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.06); color: white; padding: 0 18px; font-size: 15px; outline: none; }
.email-form button { height: 52px; padding: 0 28px; border-radius: 12px; border: none; background: #06b6d4; color: white; font-weight: 800; font-size: 15px; cursor: pointer; white-space: nowrap; }
.note { color: #475569; font-size: 13px; margin-bottom: 60px; }
.mockup { border-radius: 16px; border: 1px solid rgba(255,255,255,0.1); overflow: hidden; max-width: 800px; margin: 0 auto; box-shadow: 0 40px 80px rgba(0,0,0,0.5); }
.mockup-bar { display: flex; align-items: center; gap: 8px; padding: 12px 16px; background: rgba(255,255,255,0.04); border-bottom: 1px solid rgba(255,255,255,0.08); }
.dot { width: 10px; height: 10px; border-radius: 50%; } .red { background: #ef4444; } .yellow { background: #eab308; } .green { background: #22c55e; }
.url { margin-left: 12px; color: #475569; font-size: 12px; }
.mockup-content { display: flex; min-height: 280px; }
.sidebar { width: 160px; background: rgba(255,255,255,0.03); border-right: 1px solid rgba(255,255,255,0.06); padding: 20px 12px; }
.s-item { padding: 10px 12px; border-radius: 8px; font-size: 13px; color: #64748b; margin-bottom: 4px; } .s-item.active { background: rgba(6,182,212,0.15); color: #06b6d4; font-weight: 600; }
.main-content { flex: 1; padding: 24px; text-align: left; }
.welcome { font-size: 18px; font-weight: 700; margin-bottom: 20px; }
.cards-row { display: flex; gap: 12px; margin-bottom: 24px; }
.mini-card { flex: 1; padding: 16px; border-radius: 10px; background: rgba(255,255,255,0.05); } .mini-card strong { display: block; font-size: 24px; font-weight: 800; } .mini-card small { color: #64748b; font-size: 12px; } .mini-card.accent { background: rgba(6,182,212,0.1); }
.p-label { display: flex; justify-content: space-between; font-size: 13px; color: #94a3b8; margin-bottom: 8px; } .p-label span { color: #06b6d4; font-weight: 700; }
.p-bar { height: 6px; background: rgba(255,255,255,0.1); border-radius: 3px; } .p-fill { height: 100%; border-radius: 3px; background: linear-gradient(90deg, #06b6d4, #3b82f6); }
.logos { padding: 60px; text-align: center; border-top: 1px solid rgba(255,255,255,0.06); } .logos p { color: #475569; margin-bottom: 28px; }
.logo-row { display: flex; justify-content: center; gap: 48px; } .logo-row span { color: #334155; font-weight: 800; font-size: 18px; letter-spacing: 1px; }

