const input = document.querySelector('.email-form input');
const btn = document.querySelector('.email-form button');
btn.addEventListener('click', () => {
  if (input.value.includes('@')) {
    btn.textContent = '✓ Kaydedildi!';
    btn.style.background = '#22c55e';
    input.value = '';
    setTimeout(() => { btn.textContent = 'Erken Erişim Al'; btn.style.background = '#06b6d4'; }, 3000);
  } else {
    input.style.borderColor = '#ef4444';
    setTimeout(() => { input.style.borderColor = 'rgba(255,255,255,0.15)'; }, 2000);
  }
});
